#include <stdio.h>
#include <stdlib.h>

// Define the structure for an adjacency list
typedef struct AdjListNode {
    int vertex;
    struct AdjListNode* next;
} AdjListNode;

// Define the structure for a graph
typedef struct Graph {
    int numVertices;
    AdjListNode** adjLists;
} Graph;

// Function to create a new adjacency list node
AdjListNode* createNode(int vertex) {
    AdjListNode* newNode = (AdjListNode*) malloc(sizeof(AdjListNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->vertex = vertex;
    newNode->next = NULL;
    return newNode;
}

// Function to create a graph with given vertices
Graph* createGraph(int vertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    if (!graph) {
        printf("Memory error
");
        return NULL;
    }

    graph->numVertices = vertices;

    // Create an array to hold the adjacency lists
    graph->adjLists = (AdjListNode**) malloc(vertices * sizeof(AdjListNode*));
    for (int i = 0; i < vertices; i++) {
        graph->adjLists[i] = NULL;
    }

    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    // Add an edge from src to dest
    AdjListNode* newNode = createNode(dest);
    newNode->next = graph->adjLists[src];
    graph->adjLists[src] = newNode;
}

// Function to perform DFS
int* DFS(Graph* graph, int* color) {
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
    }

    for (int i = 0; i < graph->numVertices; i++) {
        if (visited[i] == 0) {
            if (DFSUtil(graph, i, color, visited) == 0) {
                return NULL;
            }
        }
    }

    return color;
}

// Utility function for DFS
int DFSUtil(Graph* graph, int vertex, int* color, int* visited) {
    visited[vertex] = 1;

    AdjListNode* node = graph->adjLists[vertex];
    while (node) {
        if (visited[node->vertex] == 0) {
            if (color[vertex] == -1) {
                color[node->vertex] = 1 - color[vertex];
            } else if (color[node->vertex] == color[vertex]) {
                return 0;
            }
            if (DFSUtil(graph, node->vertex, color, visited) == 0) {
                return 0;
            }
        }
        node = node->next;
    }

    return 1;
}

int main() {
    int V;
    printf("Enter the number of vertices: ");
    scanf("%d", &V);

    Graph* graph = createGraph(V);
    int* color = (int*) malloc(V * sizeof(int));
    for (int i = 0; i < V; i++) {
        color[i] = -1;
    }

    printf("Enter the number of edges: ");
    int E;
    scanf("%d", &E);
    for (int i = 0; i < E; i++) {
        int u, v;
        printf("Enter edge %d: ", i + 1);
        scanf("%d %d", &u, &v);
        addEdge(graph, u, v);
        addEdge(graph, v, u);
    }

    if (DFS(graph, color)) {
        printf("The graph is bipartite.
");
    } else {
        printf("The graph is not bipartite.
");
    }

    return 0;
}

