class Solution {
    isBipartite(V, adj) {
        let color = new Array(V).fill(-1);

        for (let i = 0; i < V; i++) {
            if (color[i] === -1) {
                if (!this.dfs(i, 0, color, adj)) {
                    return false;
                }
            }
        }
        return true;
    }

    dfs(node, col, color, adj) {
        color[node] = col;

        for (let neighbor of adj[node]) {
            if (color[neighbor] === -1) {
                if (!this.dfs(neighbor, 1 - col, color, adj)) {
                    return false;
                }
            } else if (color[neighbor] === col) {
                return false;
            }
        }
        return true;
    }
}

